import subprocess
import psutil
import time
import os

def task_func(script_path: str, timeout=10) -> dict:
    if not os.path.exists(script_path):
        raise FileNotFoundError(f"Script not found: {script_path}")

    cpu_usage = 0.0
    memory_usage = 0.0
    start_time = time.time()
    process = None

    try:
        process = subprocess.Popen([script_path], stdout=subprocess.PIPE, stderr=subprocess.PIPE)
        proc = psutil.Process(process.pid)

        last_memory_rss = 0
        interval = 0.1

        while True:
            if process.poll() is not None:
                break

            if time.time() - start_time > timeout:
                process.terminate()
                try:
                    process.wait(timeout=1)
                except subprocess.TimeoutExpired:
                    process.kill()
                break

            try:
                if not proc.is_running():
                    break

                # Accumulate CPU usage (cumulative, not averaged)
                cpu_percent = proc.cpu_percent(interval=interval)
                cpu_usage += cpu_percent

                # Get current RSS and accumulate the increment
                current_memory_rss = proc.memory_info().rss
                memory_usage += (current_memory_rss - last_memory_rss)
                last_memory_rss = current_memory_rss

            except (psutil.NoSuchProcess, psutil.AccessDenied):
                break

    except Exception as e:
        if process and process.poll() is None:
            process.terminate()
            try:
                process.wait(timeout=1)
            except subprocess.TimeoutExpired:
                process.kill()
        raise e

    finally:
        if process and process.poll() is None:
            process.terminate()
            try:
                process.wait(timeout=1)
            except subprocess.TimeoutExpired:
                process.kill()

    return {
        'CPU Usage': cpu_usage,
        'Memory Usage': int(memory_usage)
    }
