import rsa
import urllib.request
from hashlib import sha256

def task_func(url):
    try:
        with urllib.request.urlopen(url) as response:
            if response.getcode() >= 400:
                raise ValueError(f"HTTP error: {response.getcode()}")
            content = response.read()
    except urllib.error.URLError as e:
        raise urllib.error.URLError(e.reason) from e
    except Exception as e:
        raise ValueError(f"Error reaching server: {e}") from e

    try:
        hash_obj = sha256(content).digest()
        pub_key, priv_key = rsa.newkeys(2048)
        signed_hash = rsa.sign(hash_obj, priv_key, 'SHA-256')
        signed_hex = signed_hash.hex()
        return pub_key, signed_hex, hash_obj
    except rsa.pkcs1.VerificationError as e:
        raise rsa.pkcs1.VerificationError("Failed to sign hash with private key") from e
    except Exception as e:
        raise rsa.pkcs1.VerificationError(f"Signing failed: {e}") from e
