                json_data = json.loads(data)
                if isinstance(json_data, dict) and 'ip' in json_data:
                    ip = json_data['ip']
                elif isinstance(json_data, str):
                    ip = json_data
                else:
                    raise ValueError("Unexpected JSON structure")
            except json.JSONDecodeError:
                # Fall back to regex if not valid JSON
                ip_match = re.search(IP_REGEX, data)
                if ip_match:
                    ip = ip_match.group()
                else:
                    raise ValueError("No valid IP address found in the response")

            # Validate the extracted IP
            if re.fullmatch(IP_REGEX, ip):
                return ip
            else:
                raise ValueError("Extracted IP is not valid")
    except Exception as e:
        raise Exception(str(e))
