            else:
                try:
                    numerical_data[i - 1].append(float(val))
                except (ValueError, TypeError):
                    numerical_data[i - 1].append(np.nan)

    # Compute mean for each position, handling nan values
    means = []
    for i, col_data in enumerate(numerical_data):
        if not col_data:
            means.append(np.nan)
        else:
            mean_val = np.nanmean(col_data)
            means.append(mean_val)

    # Write results to file
    with open(file_name, 'w') as f:
        for i, mean_val in enumerate(means):
