                data = json.load(file)

                # Helper function to search recursively in JSON structure for substring
                def search_in_json(obj, target):
                    if isinstance(obj, dict):
                        for value in obj.values():
                            if search_in_json(value, target):
                                return True
                    elif isinstance(obj, list):
                        for item in obj:
                            if search_in_json(item, target):
                                return True
                    elif isinstance(obj, str):
                        if target in obj:
                            return True
                    return False

                if search_in_json(data, string):
                    matching_files.append(file_path)
        except (json.JSONDecodeError, IOError):
            continue

    return matching_files
