        return []
    return sorted(numbers, reverse=True)[:n]

def differ_at_one_bit_position(a, b):
    xor_result = a ^ b
    return xor_result != 0 and (xor_result & (xor_result - 1)) == 0

def find_long_words(text):
    import re
    if not text:
        return []
    words = re.findall(r'\b[a-zA-Z]+\b', text)
    return [word for word in words if len(word) >= 4]

def square_elements(lst):
    if not isinstance(lst, list):
        raise TypeError("Input must be a list")
    return [x ** 2 for x in lst if isinstance(x, (int, float))]

def min_rotations_to_same_string(s):
    n = len(s)
    if n == 0:
        return 0
    for i in range(1, n):
        if s == s[i:] + s[:i]:
            return i
    return n

def sort_matrix_by_row_sum(matrix):
    if not matrix or not all(isinstance(row, list) for row in matrix):
        return matrix
    return sorted(matrix, key=sum)

def contains_lowercase_underscore_sequence(s):
    import re
    pattern = r'^[a-z]+(?:_[a-z]+)*$'
    return bool(re.match(pattern, s)) and s != '' and not s.startswith('_') and not s.endswith('_')

def contains_duplicate(nums):
    seen = set()
    for num in nums:
        if num in seen:
            return True
        seen.add(num)
    return False

def is_one_less_than_twice_reverse(n):
    if not isinstance(n, int):
        return False
    reverse_n = int(str(abs(n))[::-1])
    return n == 2 * reverse_n - 1 if n >= 0 else False

def nth_octagonal_number(n):
    if not isinstance(n, int) or n <= 0:
        raise ValueError("Input must be a positive integer.")
    return n * (3 * n - 2)

def count_substrings_with_digit_sum_equal_length(s):
    count = 0
    n = len(s)
    for i in range(n):
        digit_sum = 0
        for j in range(i, n):
            if not s[j].isdigit():
                break
            digit_sum += int(s[j])
            length = j - i + 1
            if digit_sum == length:
                count += 1
    return count

def max_difference_pairs(tuples_list):
    if len(tuples_list) < 2:
        return 0
    max_diff = 0
    for i in range(len(tuples_list)):
        for j in range(i + 1, len(tuples_list)):
            if len(tuples_list[i]) < 2 or len(tuples_list[j]) < 2:
                continue
            try:
                diff = abs(tuples_list[i][0] - tuples_list[j][0]) + abs(tuples_list[i][1] - tuples_list[j][1])
                max_diff = max(max_diff, diff)
            except (TypeError, ValueError):
                continue
    return max_diff

def sort_tuples_by_second_value(tuples_list, reverse=False):
    if not isinstance(tuples_list, list):
        raise TypeError("Input must be a list.")
    if not all(isinstance(item, tuple) for item in tuples_list):
        raise ValueError("All items in the list must be tuples.")
    return sorted(tuples_list, key=lambda x: x[1], reverse=reverse)

def flatten_and_sum(lst):
    total = 0
    for item in lst:
        if isinstance(item, list):
            total += flatten_and_sum(item)
        elif isinstance(item, (int, float)):
            total += item
    return total

def bell_number(n):
    if n < 0:
        return 0
    if n == 0:
        return 1

    # Create a 2D array to store Bell triangle
    bell = [[0 for _ in range(n + 1)] for _ in range(n + 1)]
    bell[0][0] = 1

    for i in range(1, n + 1):
        # Explicitly set the first element of each row
        bell[i][0] = bell[i - 1][i - 1]

        for j in range(1, i + 1):
            bell[i][j] = bell[i - 1][j - 1] + bell[i][j - 1]

    return bell[n][n]

def is_monotonic(arr):
    if len(arr) <= 2:
        return True

    increasing = True
    decreasing = True

    for i in range(1, len(arr)):
        try:
            if arr[i] < arr[i-1]:
                increasing = False
            if arr[i] > arr[i-1]:
                decreasing = False
        except TypeError:
            return False

    return increasing or decreasing

def contains_sublist(main_list, sublist):
    if not isinstance(main_list, list) or not isinstance(sublist, list):
        raise TypeError("Both arguments must be lists")
    if len(sublist) > len(main_list):
        return False
    if not sublist:
        return True
    for i in range(len(main_list) - len(sublist) + 1):
        if main_list[i:i + len(sublist)] == sublist:
            return True
    return False

