def follows_sequence(text, patterns):
    if not patterns:
        return True
    if not text:
        return False

    def backtrack(text_idx, pattern_idx):
        if pattern_idx == len(patterns):
            return text_idx == len(text)
        if text_idx > len(text):
            return False

        pattern = patterns[pattern_idx]
        pattern_len = len(pattern)

        # Try to match the current pattern starting at each possible position
        # in the remaining text
        for i in range(text_idx, len(text) - pattern_len + 1):
            if text[i:i + pattern_len] == pattern:
                if backtrack(i + pattern_len, pattern_idx + 1):
                    return True
        return False

    return backtrack(0, 0)

def find_tuples_divisible_by_k(tuples_list, k):
    if k == 0:
        raise ValueError("k cannot be zero")
    return [tup for tup in tuples_list if all(isinstance(x, (int, float)) and x % k == 0 for x in tup)]

def is_divisible_by_11(n):
    n = abs(n)
    digits = str(n)
    alt_sum = 0
    for i, digit in enumerate(reversed(digits)):
        if i % 2 == 0:
            alt_sum += int(digit)
        else:
            alt_sum -= int(digit)
    return alt_sum % 11 == 0

def is_word_length_odd(word):
