def find_char_from_ascii_mod26(s):
    total_ascii = sum(ord(c) for c in s)
    mod_value = total_ascii % 26
    return chr(ord('a') + mod_value)

def newman_conway(n):
    if n == 1:
        return 1
    if n == 2:
        return 1

    seq = [0] * (n + 1)
    seq[1] = 1
    seq[2] = 1

    for i in range(3, n + 1):
        seq[i] = seq[seq[i - 1]] + seq[i - seq[i - 1]]

    return seq[n]

def get_frequency(lst):
