def multiply_and_divide(numbers):
    if not numbers:
        raise ValueError("Cannot compute with an empty list")
    product = 1
    for num in numbers:
        product *= num
    return product / len(numbers)

def decimal_to_binary(n):
    if n == 0:
        return "0"
    if n < 0:
        raise ValueError("Input must be a non-negative integer.")
    binary = ""
    while n > 0:
        binary = str(n % 2) + binary
        n //= 2
    return binary

def find_kth_element(arr, k):
    if not isinstance(k, int):
        raise TypeError("k must be an integer")
    if k < 1:
        raise IndexError("k must be at least 1")
    if not arr:
        raise IndexError("array is empty")
    if k > len(arr):
        raise IndexError("k is out of bounds")
    return arr[k - 1]

def snake_to_camel(snake_str):
    if not snake_str:
        return ""
    components = snake_str.split('_')
    # Filter out empty strings from consecutive underscores
    components = [comp for comp in components if comp]
    if not components:
        return ""
    return components[0] + ''.join(x.capitalize() for x in components[1:])

def eulerian_number(n, m):
    if m < 0 or m >= n:
        return 0
    if n == 0:
        return 1 if m == 0 else 0
    return (n - m) * eulerian_number(n - 1, m - 1) + (m + 1) * eulerian_number(n - 1, m)

def append_list_to_tuple(tup, lst):
    if not isinstance(tup, tuple):
        raise TypeError("First argument must be a tuple")
    if not isinstance(lst, (list, tuple)):
        raise TypeError("Second argument must be a list or tuple")
