def count_odd_rotations(binary_string, rotations):
    count = 0
    n = len(binary_string)

    for i in range(min(rotations, n)):
        rotated = binary_string[i:] + binary_string[:i]
        if int(rotated, 2) % 2 == 1:
            count += 1

    return count

def find_common_elements(nested_lists):
    if not nested_lists:
        return []
    common = set()
    first_list = nested_lists[0]
    if not first_list:
        return []
    common = set(first_list)
    for lst in nested_lists[1:]:
        if not lst:
            return []
        try:
            common &= set(lst)
        except TypeError:
            # Handle non-hashable elements by converting to tuples
            common = common.intersection(set(tuple(x) if isinstance(x, (list, dict)) else x for x in lst))
    return list(common)

def is_integer(s):
    if not s or not isinstance(s, str):
        return False
    s = s.strip()
    if not s:
        return False
    if s[0] in '+-' and len(s) == 1:
        return False
    return s[1:].isdigit() if s[0] in '+-' else s.isdigit()

def all_dicts_empty(dict_list):
