def convert_to_floats(lst_of_lsts):
    result = []
    for row in lst_of_lsts:
        converted_row = []
        for element in row:
            if isinstance(element, (list, tuple)):
                converted_row.append(convert_to_floats([element])[0])
            else:
                try:
                    converted_row.append(float(element))
                except (ValueError, TypeError):
                    converted_row.append(element)
        result.append(converted_row)
    return result

def find_unique_element(nums):
    if not nums:
        return None
    if len(nums) == 1:
        return nums[0]

    left, right = 0, len(nums) - 1

    while left < right:
        mid = (left + right) // 2

        # Ensure mid is even to compare pairs
        if mid % 2 == 1:
            mid -= 1

        # If the pair (mid, mid+1) is the same, unique element is on the right
        if nums[mid] == nums[mid + 1]:
            left = mid + 2
        else:
            right = mid

    return nums[left]

def max_absolute_product(pairs):
    if not pairs:
        return 0
    max_product = float('-inf')
    for a, b in pairs:
        product = abs(a * b)
        if product > max_product:
            max_product = product
    return max_product

def sum_amicable_numbers(n):
    def sum_of_divisors(num):
        divisors_sum = 1
        for i in range(2, int(num ** 0.5) + 1):
            if num % i == 0:
                divisors_sum += i
                if i != num // i:
                    divisors_sum += num // i
        return divisors_sum

    amicable_sum = 0
    visited = set()

    for i in range(2, n + 1):
        if i in visited:
            continue
        sum_i = sum_of_divisors(i)
        if sum_i != i and sum_i <= n:
            sum_sum_i = sum_of_divisors(sum_i)
            if sum_sum_i == i:
                amicable_sum += i + sum_i
                visited.add(i)
                visited.add(sum_i)

    return amicable_sum

import cmath

def get_angle(z):
    if z == 0:
        raise ValueError("Cannot compute angle of zero")
    return cmath.phase(z)

def max_diff_zeros_ones(s):
    max_diff = float('-inf')
    current_diff = 0

    for char in s:
        if char == '0':
            current_diff += 1
        else:
            current_diff -= 1

        max_diff = max(max_diff, current_diff)
        if current_diff < 0:
            current_diff = 0

    return max_diff if max_diff != float('-inf') else 0

def sum_of_common_divisors(a, b):
    total = 0
    n = min(a, b)
    i = 1
    while i * i <= n:
        if n % i == 0:
            if a % i == 0 and b % i == 0:
                total += i
            if i != n // i and a % (n // i) == 0 and b % (n // i) == 0:
                total += n // i
        i += 1
    return total

