def is_magic_square(matrix):
    if not matrix or not matrix[0]:
        return False

    n = len(matrix)
    if any(len(row) != n for row in matrix):
        return False

    # Check for non-numeric elements
    for row in matrix:
        for element in row:
            if not isinstance(element, (int, float)):
                return False

    # Check if all numbers are distinct and form a sequence from 1 to n²
    expected_set = set(range(1, n * n + 1))
    actual_set = set()
    for row in matrix:
        for element in row:
            if not isinstance(element, int) or element < 1 or element > n * n:
                return False
            actual_set.add(element)

    if actual_set != expected_set:
        return False

    target_sum = sum(matrix[0])

    # Check rows
    for row in matrix:
        if sum(row) != target_sum:
            return False

    # Check columns
    for col in range(n):
        if sum(matrix[row][col] for row in range(n)) != target_sum:
            return False

    # Check main diagonal
    if sum(matrix[i][i] for i in range(n)) != target_sum:
        return False

    # Check anti-diagonal
    if sum(matrix[i][n-1-i] for i in range(n)) != target_sum:
        return False

    return True

def find_max_frequency_item(lst):
