    max_freq = max(freq.values())
    return [item for item, count in freq.items() if count == max_freq]

def reverse_vowels(s):
    vowels = set('aeiouAEIOU')
    s_list = list(s)
    left = 0
    right = len(s) - 1

    while left < right:
        if s_list[left] not in vowels:
            left += 1
        elif s_list[right] not in vowels:
            right -= 1
        else:
            s_list[left], s_list[right] = s_list[right], s_list[left]
            left += 1
            right -= 1

    return ''.join(s_list)

def zero_to_nonzero_ratio(arr):
    if not arr:
        return 0.0
    zero_count = sum(1 for x in arr if x == 0)
    non_zero_count = len(arr) - zero_count
    if non_zero_count == 0:
        return float('inf')
    return zero_count / non_zero_count

def can_be_sum_of_nonzero_powers_of_2(n):
