def max_difference(arr):
    if len(arr) < 2:
        return 0
    min_val = arr[0]
    max_diff = 0
    for i in range(1, len(arr)):
        if arr[i] < min_val:
            min_val = arr[i]
        else:
            max_diff = max(max_diff, arr[i] - min_val)
    return max_diff

def extended_gcd(a, b):
    if a == 0:
        return b, 0, 1
    gcd, x1, y1 = extended_gcd(b % a, a)
    x = y1 - (b // a) * x1
    y = x1
    return gcd, x, y

def solve_linear_diophantine(a, b, n):
    gcd, x, y = extended_gcd(abs(a), abs(b))
    if n % gcd != 0:
        return None
    factor = n // gcd
    x *= factor
    y *= factor
    if a < 0:
        x = -x
    if b < 0:
        y = -y
    return (x, y)

def remove_elements_from_list(main_list, elements_to_remove):
    if not isinstance(elements_to_remove, (list, set)):
        raise TypeError("elements_to_remove must be a list or set")
    remove_set = set(elements_to_remove)
    return [item for item in main_list if item not in remove_set]

def calculate_sum(n):
    k = n // 2 + 1
    return k * n - 2 * k * (k - 1) // 2

def polygon_area(side_length, num_sides):
    import math
    if not isinstance(num_sides, int) or num_sides < 3:
        raise ValueError("Number of sides must be an integer greater than or equal to 3.")
    if side_length <= 0:
        raise ValueError("Side length must be positive.")
    area = (num_sides * side_length**2) / (4 * math.tan(math.pi / num_sides))
    return area

def sum_of_divisors(n):
    if n <= 0:
        raise ValueError("Input must be a positive integer.")
    divisors_sum = 0
    i = 1
    while i * i <= n:
        if n % i == 0:
            divisors_sum += i
            if i != n // i:
                divisors_sum += n // i
        i += 1
    return divisors_sum

def are_divisor_sums_equal(a, b):
    if a <= 0 or b <= 0:
        raise ValueError("Both inputs must be positive integers.")
    return sum_of_divisors(a) == sum_of_divisors(b)

def count_alphabet_position_chars(s):
