        return True
    first_type = type(tup[0])
    return all(type(x) == first_type for x in tup)

def is_majority_element(arr, n, target):
    if n == 0:
        return False

    # Find the first occurrence of target using binary search
    left = 0
    right = n - 1
    first_pos = -1
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == target:
            first_pos = mid
            right = mid - 1
        elif arr[mid] < target:
            left = mid + 1
        else:
            right = mid - 1

    # If target is not found, return False
    if first_pos == -1:
        return False

    # Find the last occurrence of target
    left = first_pos
    right = n - 1
    last_pos = -1
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == target:
            last_pos = mid
            left = mid + 1
        elif arr[mid] < target:
            left = mid + 1
        else:
            right = mid - 1

    # Calculate count of target
    count = last_pos - first_pos + 1

    # Check if count is more than n/2
    return count > n // 2

def count_set_bits(n):
    count = 0
    while n:
        count += n & 1
        n &= n - 1
    return count

def all_bits_unset_in_range(n, left, right):
    if left < 0 or right < left or right >= 64:
        return True  # Invalid range, assume no bits set
    mask = ((1 << (right - left + 1)) - 1) << left
    return (n & mask) == 0

