def max_bitonic_sum(arr):
    n = len(arr)
    if n == 0:
        return 0

    # dp_inc[i] stores the maximum sum of increasing subsequence ending at index i
    dp_inc = [0] * n
    for i in range(n):
        dp_inc[i] = arr[i]
        for j in range(i):
            if arr[j] < arr[i]:
                dp_inc[i] = max(dp_inc[i], dp_inc[j] + arr[i])

    # dp_dec[i] stores the maximum sum of decreasing subsequence starting at index i
    dp_dec = [0] * n
    for i in range(n - 1, -1, -1):
        dp_dec[i] = arr[i]
        for j in range(i + 1, n):
            if arr[j] < arr[i]:
                dp_dec[i] = max(dp_dec[i], dp_dec[j] + arr[i])

    # Find maximum sum of bitonic subsequence
    max_sum = 0
    for i in range(n):
        # Bitonic sequence with peak at i
        bitonic_sum = dp_inc[i] + dp_dec[i] - arr[i]  # subtract arr[i] as it's counted twice
        max_sum = max(max_sum, bitonic_sum)

    return max_sum
