def max_subarray_sum_repeated(arr, k):
    n = len(arr)
    if n == 0:
        return 0

    total_sum = sum(arr)

    def kadane(nums):
        max_ending_here = max_so_far = nums[0]
        for i in range(1, len(nums)):
            max_ending_here = max(nums[i], max_ending_here + nums[i])
            max_so_far = max(max_so_far, max_ending_here)
        return max_so_far

    if k == 1:
        return kadane(arr)

    max_kadane = kadane(arr)

    if total_sum < 0:
        # When total sum is negative, the best subarray cannot span more than two copies
        # So we only need to check at most two repetitions
        doubled_arr = arr + arr
        return kadane(doubled_arr)

    # When total sum is positive, we can include full copies in the middle
    # The optimal subarray will be: (k-2) full copies + max prefix + max suffix
    max_prefix = arr[0]
    current = 0
    for i in range(n):
        current += arr[i]
        max_prefix = max(max_prefix, current)

    max_suffix = arr[n-1]
    current = 0
    for i in range(n-1, -1, -1):
        current += arr[i]
        max_suffix = max(max_suffix, current)

    return (k - 2) * total_sum + max_prefix + max_suffix

