def num_ways(n, k):
    if n == 0:
        return 0
    if n == 1:
        return k
    if n == 2:
        return k * k

    same = k  # ways where the last two posts have the same color
    diff = k * (k - 1)  # ways where the last two posts have different colors

    for i in range(3, n + 1):
        new_same = diff  # can only have same color if previous two were different
        new_diff = (same + diff) * (k - 1)  # can have different color regardless
        same, diff = new_same, new_diff

    return same + diff

