def third_side(a, b, c=None):
    if c is None:
        # c is the hypotenuse, find it using Pythagorean theorem
        return (a**2 + b**2)**0.5
    else:
        # c is known, find the missing leg
        if c <= a or c <= b:
            raise ValueError("Hypotenuse must be greater than either leg")
        return (c**2 - a**2)**0.5 if b is None else (c**2 - b**2)**0.5

