def max_sum_increasing_subsequence_with_k(arr, i, k):
    if i >= k or k >= len(arr) or i < 0:
        return 0

    # dp[j] represents the maximum sum of increasing subsequence ending at index j
    dp = [0] * len(arr)

    # Initialize dp with the value at each index
    for j in range(len(arr)):
        dp[j] = arr[j]

    # Fill dp array for indices from 0 to k
    for j in range(1, k + 1):
        for prev in range(j):
            if arr[prev] < arr[j]:
                dp[j] = max(dp[j], dp[prev] + arr[j])

    # Find the maximum sum of increasing subsequence ending at or before i
    max_prefix_sum = 0
    for j in range(i + 1):
        if arr[j] < arr[k]:  # Only consider extending if we can include k
            max_prefix_sum = max(max_prefix_sum, dp[j])

    # If we can extend a valid subsequence ending at or before i to include k
    if max_prefix_sum > 0:
        return max_prefix_sum + arr[k]
    else:
        # If no valid subsequence before i, but we still need to include k
        # We can only include k if there's a valid element before it, but none found
        # So return 0 as no valid increasing subsequence including k and an element before it
        return 0

def set_leftmost_unset_bit(n):
    if n == 0:
        return 1
    bit_length = n.bit_length()
    for i in range(bit_length - 1, -1, -1):
        if not (n & (1 << i)):
            return n | (1 << i)
    return n | (1 << bit_length)

