def lists_to_nested_dict(keys, values_list):
    if not keys or not values_list:
        return {}
    if len(keys) == 1:
        return {keys[0]: values_list}
    result = {}
    for item in values_list:
        if not isinstance(item, (list, tuple)) or len(item) < len(keys):
            continue
        key = item[0]
        if key not in result:
            result[key] = []
        result[key].append(item[1:])
    return {k: lists_to_nested_dict(keys[1:], v) for k, v in result.items()}

def max_sum(n, memo=None):
    if memo is None:
        memo = {}
    if n in memo:
        return memo[n]
    if n == 0:
        return 0
    result = max(max_sum(n//2, memo) + max_sum(n//3, memo) + max_sum(n//4, memo) + max_sum(n//5, memo), n)
    memo[n] = result
    return result

