def sum_perrin(n):
    if n < 0:
        return 0
    if n == 0:
        return 3
    if n == 1:
        return 3 + 0
    if n == 2:
        return 3 + 0 + 2

    a, b, c = 3, 0, 2  # P(0), P(1), P(2)
    total = a + b + c

    for i in range(3, n + 1):
        next_perrin = b + a  # P(i) = P(i-2) + P(i-3)
        total += next_perrin
        a, b, c = b, c, next_perrin

    return total

