        return 0

    nums.sort()
    n = len(nums)
    dp = [1] * n
    parent = [-1] * n

    for i in range(1, n):
        for j in range(i):
            if nums[i] % nums[j] == 0 and dp[j] + 1 > dp[i]:
                dp[i] = dp[j] + 1
                parent[i] = j

    max_size = max(dp)
    max_index = dp.index(max_size)

    subset = []
    while max_index != -1:
        subset.append(nums[max_index])
        max_index = parent[max_index]

    return max_size

