import os
import sys
import importlib
from pkgutil import iter_modules

def task_func(package_name):
    try:
        package = importlib.import_module(package_name)
        package_path = os.path.dirname(package.__file__)
        if package_path not in sys.path:
            sys.path.append(package_path)

        module_names = set()
        for _, module_name, _ in iter_modules([package_path]):
            module_names.add(module_name)

        # Recursively add all submodules and subpackages
        def add_submodules(package_path, prefix=""):
            for _, module_name, ispkg in iter_modules([package_path]):
                full_name = f"{prefix}{module_name}" if prefix else module_name
                module_names.add(module_name)
                if ispkg:
                    try:
                        subpackage = importlib.import_module(f"{package_name}.{full_name}")
                        subpackage_path = os.path.dirname(subpackage.__file__)
                        if subpackage_path not in sys.path:
                            sys.path.append(subpackage_path)
                        add_submodules(subpackage_path, f"{full_name}.")
                    except ImportError:
                        continue

        add_submodules(package_path)

        return sorted(list(module_names))
    except ImportError as e:
        raise ImportError(f"pip install {package_name}") from e
