import subprocess
import psutil
import time
import os

def task_func(script_path: str, timeout=10) -> dict:
    if not os.path.exists(script_path):
        raise FileNotFoundError(f"Script not found: {script_path}")

    process = None
    try:
        process = subprocess.Popen([script_path], stdout=subprocess.PIPE, stderr=subprocess.PIPE)
        proc = psutil.Process(process.pid)
        start_time = time.time()
        cpu_usage = 0.0
        memory_usage = 0.0
        last_cpu_time = proc.cpu_times().user + proc.cpu_times().system

        while True:
            if process.poll() is not None:
                break

            if time.time() - start_time > timeout:
                process.terminate()
                try:
                    process.wait(timeout=1)
                except subprocess.TimeoutExpired:
                    process.kill()
                break

            try:
                if not proc.is_running():
                    break

                current_cpu_time = proc.cpu_times().user + proc.cpu_times().system
                cpu_delta = current_cpu_time - last_cpu_time
                elapsed_time = time.time() - start_time
                if elapsed_time > 0:
                    cpu_usage += (cpu_delta / elapsed_time) * 100.0
                last_cpu_time = current_cpu_time

                memory_info = proc.memory_info()
                memory_usage += memory_info.rss

            except (psutil.NoSuchProcess, psutil.AccessDenied):
                break

        return {
            'CPU Usage': cpu_usage,
            'Memory Usage': int(memory_usage)
        }

    except Exception as e:
        if process and process.poll() is None:
            process.terminate()
            try:
                process.wait(timeout=1)
            except subprocess.TimeoutExpired:
                process.kill()
        raise e
    finally:
        if process and process.poll() is None:
            process.terminate()
            try:
                process.wait(timeout=1)
            except subprocess.TimeoutExpired:
                process.kill()
