import re
import json
from collections import Counter

def task_func(json_str, top_n=10):
    # Define URL pattern that matches valid URLs without unescaped quotes or brackets
    url_pattern = re.compile(r'https?://[^\s"<>{}|\\^`[\]]+(?:[^\s"<>{}|\\^`[\]]|$)')

    # Parse JSON string to extract values
    try:
        data = json.loads(json_str)
    except json.JSONDecodeError:
        return {}

    # Extract all strings from the JSON structure
    all_strings = []

    def extract_strings(obj):
        if isinstance(obj, str):
            all_strings.append(obj)
        elif isinstance(obj, dict):
            for value in obj.values():
                extract_strings(value)
        elif isinstance(obj, list):
            for item in obj:
                extract_strings(item)

    extract_strings(data)

    # Find all URLs in the strings
    urls = []
    for string in all_strings:
        found_urls = url_pattern.findall(string)
        urls.extend(found_urls)

    # Count frequency of each URL
    url_counts = Counter(urls)

    # Return top_n most common URLs
    return dict(url_counts.most_common(top_n))
