import subprocess
import time
import json
import platform
LOGFILE_PATH = "logfile.log"

def task_func(interval, duration):
    if interval <= 0 or duration <= 0:
        raise ValueError("Both interval and duration must be greater than zero.")

    log_data = []
    start_time = time.time()

    while (time.time() - start_time) < duration:
        try:
            if platform.system() == "Windows":
                result = subprocess.run(
                    ["wmic", "cpu", "get", "loadpercentage"],
                    capture_output=True,
                    text=True,
                    timeout=5
                )
                output = result.stdout.strip()
                cpu_usage = 0.0
                for line in output.split('\n'):
                    if line.strip().isdigit():
                        cpu_usage = float(line.strip())
                        break
            else:
                result = subprocess.run(
                    ["top", "-bn1"],
                    capture_output=True,
                    text=True,
                    timeout=5
                )
                output = result.stdout
                cpu_usage = 0.0
                for line in output.split('\n'):
                    if line.strip().startswith("Cpu(s):"):
                        # Extract the percentage from the line
                        parts = line.split(',')
                        for part in parts:
                            if '%' in part:
                                cpu_usage_str = part.strip().replace('%', '')
                                try:
                                    cpu_usage = float(cpu_usage_str)
                                    break
                                except ValueError:
                                    cpu_usage = 0.0
                        break
        except (subprocess.TimeoutExpired, subprocess.CalledProcessError, Exception):
            cpu_usage = 0.0

        timestamp = time.time()
        log_data.append({
            "timestamp": timestamp,
            "cpu_usage": cpu_usage
        })

        # Calculate time to next interval
        elapsed = time.time() - start_time
        if elapsed >= duration:
            break
        sleep_time = interval - (time.time() - start_time) % interval
        if sleep_time > 0:
            time.sleep(sleep_time)

    try:
        with open(LOGFILE_PATH, 'w') as f:
            json.dump(log_data, f, indent=4)
        return LOGFILE_PATH
    except IOError:
        return None
