import re
import pandas as pd

def task_func(df: pd.DataFrame, column_name: str, pattern: str) -> pd.DataFrame:
    if not pattern:
        return df.copy()

    # Escape regex special characters in the pattern to match literal strings
    escaped_pattern = re.escape(pattern)

    def reverse_matching_words(text):
        words = text.split()
        matching_words = []
        non_matching_words = []

        for word in words:
            if re.search(escaped_pattern, word):
                matching_words.append(word)
            else:
                non_matching_words.append(word)

        # Reverse the order of matching words while keeping non-matching in original order
        matching_words.reverse()

        # Reconstruct the sentence maintaining original positions
        result_words = []
        match_idx = 0
        non_match_idx = 0

        for word in words:
            if re.search(escaped_pattern, word):
                result_words.append(matching_words[match_idx])
                match_idx += 1
            else:
                result_words.append(non_matching_words[non_match_idx])
                non_match_idx += 1

        return ' '.join(result_words)

    # Check if column exists
    if column_name not in df.columns:
        return df.copy()

    df_copy = df.copy()
    df_copy[column_name] = df_copy[column_name].astype(str).apply(reverse_matching_words)
    return df_copy
