import csv
import collections

def task_func(file_name):
    try:
        with open(file_name, 'r', newline='', encoding='utf-8') as file:
            reader = csv.reader(file)
            headers = next(reader, None)
            if not headers:
                return {}

            # Initialize counters for each column
            counters = {header: collections.Counter() for header in headers}
            has_data = False

            for row in reader:
                has_data = True
                for i, value in enumerate(row):
                    if value.strip() != '':
                        col_name = headers[i]
                        counters[col_name][value] += 1

            # If no data was read (only headers), return empty dict
            if not has_data:
                return {}

            result = {}
            for col_name, counter in counters.items():
                if not counter:
                    result[col_name] = None
                else:
                    max_count = max(counter.values())
                    most_common_values = [val for val, count in counter.items() if count == max_count]
                    most_common_values.sort()
                    result[col_name] = most_common_values[0]
            return result
    except Exception:
        return {}
