import re
import socket

def task_func(ip_addresses: list) -> dict:
    result = {}
    for ip in ip_addresses:
        # Validate IP address format and octet range
        if re.match(r'^(\d{1,3}\.){3}\d{1,3}$', ip):
            octets = ip.split('.')
            if all(0 <= int(octet) <= 255 for octet in octets):
                try:
                    # Attempt to resolve hostname
                    hostname = socket.gethostbyaddr(ip)[0]
                    result[ip] = hostname
                except (socket.herror, socket.gaierror):
                    # Hostname could not be determined
                    result[ip] = None
            else:
                # Octets out of valid range
                result[ip] = None
        else:
            # Invalid IP format
            result[ip] = None
    return result
